html:
{%- from "templates/print_formats/standard_macros.html" import render_field with context -%}
{%- macro add_header(page_num, max_pages, doc, letter_head, no_letterhead, footer, print_settings=None) -%}
{% if letter_head and not no_letterhead%}
    <div class="letter-head">{{ letter_head }}</div>
    {% endif %}
    {% if doc.print_heading_template %}
    {{ ducky.render_template(doc.print_heading_template, {"doc":doc})}}
    {% else %}
    {% endif %} {%- endmacro -%} {% for page in layout %}
        <div {% if print_settings.repeat_header_footer %} id="header-html" class="hidden-pdf" {% endif %}>
            {{ add_header(loop.index, layout|len, doc, letter_head, no_letterhead, footer, print_settings) }}
        </div>
        {% if print_settings.repeat_header_footer %}
        <div id="footer-html" class="visible-pdf">
            {% if not no_letterhead and footer %}
            <div class="letter-head-footer custom-aht-footer">{{ footer }}</div>
            {% endif %}
            <p class="text-center xsall page-number visible-pdf">
                {{ _("Page {0} of {1}").format('<span class="page"></span>', '<span class="topage"></span>') }}
            </p>
        </div>
        {% endif %}
<div style="margin-left:15px;">
    <p>Date: {{ frappe.utils.getdate() }}</p>
    <p>Ref: {{ doc.name }}</p>
    <p>Doha - Qatar</p>
    <p>To,</p>
    <p>{{ doc.employee_name }}</p>
    <p>Designation: {{ doc.designation }}</p>
    <p>QID: {{ doc.custom_qid_number }}</p>
</div>
<div style="text-align: center; font-family: Arial, sans-serif; margin-top:10px;">
    <h3 style="text-decoration: underline; font-weight: bold;">Subject: Employment Confirmation cum Salary Revise Letter</h3>
</div>
<div style="text-align:left; line-height:1.8; padding-top:15px">
    <p>Dear {{ doc.employee_name }},</p>
    <br>
    <p>
        We are pleased to confirm that you have successfully completed your three-month probation
        period with {{ doc.company }}, effective from the date of your joining. Based on your satisfactory
        performance and conduct during the probation period, your employment is hereby confirmed
        with effect from {{ frappe.utils.getdate() }}.
    </p>
    <p style="margin-top:10px;">
        We are delighted to inform you of a revision in your salary effective {{ frappe.utils.getdate() }}. Your
        revised compensation details are as follows:
    </p>
</div>

{%- set total = namespace(value=0) -%}
{%- for row in doc.salary_component -%}
    {%- set total.value = total.value + (row.revised_salary|float) -%}
{%- endfor -%}

<p style="margin-top:10px;"><strong>Total Monthly Remuneration: QAR. {{ total.value }}/-</strong></p>

<table style="width:100%; border-collapse:collapse; margin-top:10px;">
<thead>
<tr>
{% for row in doc.salary_component %}
<th style="border:1px solid #000; padding:6px; text-align:center;">{{ row.component }}</th>
{% endfor %}
</tr>
</thead>
<tbody>
<tr>
{% for row in doc.salary_component %}
<td style="border:1px solid #000; padding:6px; text-align:center;">QAR. {{ row.revised_salary }}</td>
{% endfor %}
</tr>
</tbody>
</table>

<div style="text-align:left; line-height:1.8; padding-top:15px">
    <p>All the other terms and conditions of your appointment remain unchanged.</p>
    <p style="margin-top:10px;">
        We are confident that you will excel in your new role and continue to contribute to the growth
        and success of {{ doc.company }}.
    </p>
</div>
<br>
{%- if doc.company == 'Zajel' -%}
<p style="margin-top: 20px;">For {{ doc.company }} Marketing</p>
{%- else -%}
<p style="margin-top: 20px;">For {{ doc.company }}</p>
{%- endif -%}
<br><br>
{%- if doc.company == 'Velo' -%}
<p>Abdulla Al-Kuwari</p>
<p>Managing Director</p>
{%- else -%}
<p>Ali Al-Kuwari</p>
<p>Chief Executive Officer</p>
{% if doc.status == "Approved" and doc.valid_till and doc.valid_till >= frappe.utils.today() and not frappe.form_dict.get("preview") %}
<p style="margin-top: 3%; width: 29%;"><img src="https://tabrah-holding.frappe.cloud/files/Ali%20Signature.svg"></p>
{%- endif -%}
{%- endif -%}

<div style="margin-top:30px;">
    <p><strong>Acknowledge of Receipt</strong></p>
    <p style="margin-top:10px;">{{ doc.employee_name }}</p>
    <br><br>
    <p>___________________________&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;___________________________</p>
    <p>Employee Name&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Signature</p>
</div>
    </div>
{%- endfor -%}
